import{_ as e,o,c as a,aa as n}from"./chunks/framework.GPvTQ_Wl.js";const p=JSON.parse('{"title":"Technical Limitations & Constraints","description":"Understand the technical limitations and constraints of modding the Total War: Rome II and Attila engine. Coverage of UI restrictions, console input, and battle mode scripting.","frontmatter":{"title":"Technical Limitations & Constraints","description":"Understand the technical limitations and constraints of modding the Total War: Rome II and Attila engine. Coverage of UI restrictions, console input, and battle mode scripting."},"headers":[],"relativePath":"guide/technical-limitations.md","filePath":"guide/technical-limitations.md","lastUpdated":1776974472000}'),i={name:"guide/technical-limitations.md"};function s(r,t,l,c,h,u){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h1><h2 id="mod-scope-philosophy" tabindex="-1">Mod Scope &amp; Philosophy <a class="header-anchor" href="#mod-scope-philosophy" aria-label="Permalink to &quot;Mod Scope &amp; Philosophy&quot;">​</a></h2><p>ConsulScriptum is a high-level automation and troubleshooting tool, <strong>not a low-level engine hack</strong>. It is designed to be powerful while remaining strictly non-invasive:</p><table tabindex="0"><thead><tr><th style="text-align:left;">What it IS</th><th style="text-align:left;">What it is NOT</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Non-invasive</strong> (.pack file mod).</td><td style="text-align:left;">A executable hack / external dll.</td></tr><tr><td style="text-align:left;">A high-level interface for official Lua APIs.</td><td style="text-align:left;">A low-level hook into internal game APIs.</td></tr><tr><td style="text-align:left;">A tool for changing current game state.</td><td style="text-align:left;">A way to modify how the game loads its own files.</td></tr><tr><td style="text-align:left;">A bridge for external script execution.</td><td style="text-align:left;">A bypass for core engine constraints.</td></tr></tbody></table><hr><div class="tip custom-block"><p class="custom-block-title">Help Improve This Project</p><p>Most of the limitations described below are due to hardcoded constraints of the game engine&#39;s UI system. If you are a modder and know a technical workaround for any of these issues (especially regarding keyboard events, custom fonts, or input focus), please <a href="https://discord.gg/6vm2M94vhX" target="_blank" rel="noreferrer">get in touch on Discord</a> or <a href="https://github.com/bukowa/ConsulScriptum/issues" target="_blank" rel="noreferrer">open an issue on GitHub</a>.</p></div><h2 id="console-input" tabindex="-1">Console input <a class="header-anchor" href="#console-input" aria-label="Permalink to &quot;Console input&quot;">​</a></h2><p>The console input component is a basic game engine TextInput element, which has several hardcoded restrictions that cannot be modified via scripts.</p><p><strong>No Enter key.</strong> The game does not capture the &quot;Enter&quot; key as a submission trigger for this UI component. You must click the <strong>Send</strong> button to execute your input.</p><p><strong>No arrow key history navigation.</strong> Keyboard events like the Up (↑) and Down (↓) arrow keys are not exposed to the modding API for this field. Use the on-screen <strong>↑</strong> and <strong>↓</strong> buttons next to the input to cycle through your command history.</p><p><strong>Locked cursor in history.</strong> When you restore a command from history using the arrow buttons, the cursor remains locked at the end of the line. You cannot click within the text or use the mouse to reposition the cursor for partial editing.</p><p><strong>No tab autocomplete.</strong> Standard Lua or console-style autocompletion (pressing Tab) is not supported by the game&#39;s internal text fields.</p><p><strong>Input truncation (Character Limit).</strong> The game&#39;s input buffer silently truncates long strings, usually around 100-255 characters. If you paste a long script, the console may only receive the first few lines, leading to syntax errors like <code>unfinished string near &#39;&lt;eof&gt;&#39;</code>.</p><div class="tip custom-block"><p class="custom-block-title">Multi-line Scripts</p><p>The console is best for one-liners or running predefined commands.<br>For anything longer or more complex, use <a href="./scriptum-manual">Scriptum</a> to run files directly from your disk.</p></div><h2 id="console-output" tabindex="-1">Console output <a class="header-anchor" href="#console-output" aria-label="Permalink to &quot;Console output&quot;">​</a></h2><p><strong>You cannot copy text directly from the UI.</strong> The output area is a read-only text component. Selecting, highlighting, or copying text with the mouse within the game window is not possible.</p><p><strong>How to copy output:</strong> All console activity is automatically mirrored to a file called <code>consul.output</code> in your game root folder. Open this file in a text editor (like Notepad++) to copy, search, or share your results.</p><p><strong>The scroll slider does not auto-reset.</strong> When new text is added, the scrollbar may not automatically jump to the bottom. You may need to scroll manually to see the latest results. Clicking <strong>Clear</strong> can help keep the view manageable.</p><h2 id="scriptum-panel" tabindex="-1">Scriptum panel <a class="header-anchor" href="#scriptum-panel" aria-label="Permalink to &quot;Scriptum panel&quot;">​</a></h2><p><strong>Slot Limit (10 Scripts).</strong> The panel is currently hard-capped at 10 script buttons. This is not a random number, but a technical compromise:</p><ul><li><strong>Rome II</strong>: The UI engine cannot create components on the fly. All 10 buttons are pre-built into the interface files.</li><li><strong>Attila</strong>: While it technically supports dynamic lists, the 10-slot limit is maintained to keep the experience consistent across both games.</li></ul><div class="tip custom-block"><p class="custom-block-title">Pro Tip: Master Scripts</p><p>If you run out of slots, you can create a &quot;Master Script&quot; that uses dofile() to execute multiple other scripts in sequence, or use the console to run one-off files.</p><p><strong>Need more slots?</strong> Please <a href="https://github.com/bukowa/ConsulScriptum" target="_blank" rel="noreferrer">reach out via GitHub</a>.</p></div><h2 id="battle-mode" tabindex="-1">Battle mode <a class="header-anchor" href="#battle-mode" aria-label="Permalink to &quot;Battle mode&quot;">​</a></h2><h3 id="battle-mode-support-rome-ii-attila" tabindex="-1">Battle Mode Support (Rome II &amp; Attila) <a class="header-anchor" href="#battle-mode-support-rome-ii-attila" aria-label="Permalink to &quot;Battle Mode Support (Rome II &amp; Attila)&quot;">​</a></h3><p>The console does not show in battle by default because the battle interface is not loaded by default by the game engine.</p><p><strong>Workaround</strong>: The mod can force the campaign UI (and thus the console) to load during campaign battles. This is achieved via a custom battlefield override command.</p><ul><li><strong>How to enable</strong>: Run <code>/use_in_battle</code> while inside a campaign session, then start your battle. Note that this command <strong>only works within an active campaign session</strong>.</li><li><strong>Status</strong>: Experimental for both Rome II and Attila.</li></ul><h2 id="total-war-attila" tabindex="-1">Total War: Attila <a class="header-anchor" href="#total-war-attila" aria-label="Permalink to &quot;Total War: Attila&quot;">​</a></h2><p>The Attila implementation is currently considered <strong>Alpha</strong>.</p><p><strong>Legacy UI Files.</strong> To maintain a unified experience and ensure stability, the Attila version reuses several core UI components and layout logic from the Rome II version. Because of this &quot;frankenstein&quot; approach, minor visual glitches or alignment issues in the console may occur.</p><p><strong>Experimental Status.</strong> While the core features (Consul Scripts, Scriptum, and Lua Console) are functional, the engine differences between the two games mean that Attila is inherently more experimental. That said, the fact that the Rome II logic &quot;just works&quot; in Attila is a testament to the underlying engine similarities.</p><div class="warning custom-block"><p class="custom-block-title">Bug Reports</p><p>If you encounter a UI crash or a script that behaves differently in Attila than in Rome II, please <a href="https://github.com/bukowa/ConsulScriptum/issues" target="_blank" rel="noreferrer">open an issue</a>.</p></div><hr>',33)])])}const m=e(i,[["render",s]]);export{p as __pageData,m as default};
